    def _clean_path(self, path):
        p = path.strip().strip('\'"')
        if platform.system() == "Windows":
            # 统一处理斜杠
            if p.startswith("//?/"):
                p = p[4:]
            if p.startswith("\\\\?\\"):
                p = p[4:]
            p = os.path.normpath(p)
            # 如果是绝对路径并且没有加突破 260 字符的前缀，强行加上
            if os.path.isabs(p) and not p.startswith("\\\\?\\"):
                p = "\\\\?\\" + p
        return p

