    def _on_book_slot_change(self, value):
        label = str(value or "任务1")
        m = re.search(r"(\d+)", label)
        new_index = int(m.group(1)) - 1 if m else 0
        new_index = max(0, min(MAX_PARALLEL_BOOK_TASKS - 1, new_index))
        if new_index == getattr(self, "active_slot_index", 0):
            return
        self._capture_active_slot_from_ui()
        try:
            save_task_page_settings({"slots": self.book_slots})
        except Exception:
            pass
        self.active_slot_index = new_index
        global state
        state = self.book_slots[self.active_slot_index]
        self._load_slot_to_ui(state)
        self._update_task_page_ui()

