    def _cell_font(self, size: int = 12, weight: str | None = None):
        """统一使用圆润亲和字体，形成更柔和的 严谨医学插画风格界面。"""
        kwargs = {"family": getattr(self, "ui_font_family", FRIENDLY_CELL_FALLBACK_FONT), "size": int(size)}
        if weight:
            kwargs["weight"] = weight
        return ctk.CTkFont(**kwargs)

    def _apply_friendly_cell_fonts(self, widget=None):
        """递归统一控件字体，同时尽量保留原来的字号和粗细。"""
        if ctk is None:
            return
        root = widget or self.root
        family = getattr(self, "ui_font_family", FRIENDLY_CELL_FALLBACK_FONT)

        def _font_from_current(current):
            size, weight = 12, None
            try:
                if hasattr(current, "cget"):
                    size = int(abs(current.cget("size") or size))
                    weight = current.cget("weight") or None
                elif isinstance(current, (tuple, list)):
                    if len(current) >= 2:
                        size = int(abs(current[1]))
                    if len(current) >= 3:
                        weight = str(current[2])
            except Exception:

                pass
            try:
                return ctk.CTkFont(family=family, size=max(9, size), weight=weight) if weight else ctk.CTkFont(family=family, size=max(9, size))
            except Exception:
                return current

        def _walk(w):
            try:
                current = w.cget("font")
                w.configure(font=_font_from_current(current))
            except Exception:
                pass
            try:
                for child in w.winfo_children():
                    _walk(child)
            except Exception:
                pass

        _walk(root)
        try:
            style = ttk.Style()
            style.configure("Treeview", font=(family, 11), rowheight=32, background="#FFFFFF", fieldbackground="#FFFFFF", foreground="#1D1D1F")
            style.configure("Treeview.Heading", font=(family, 11, "bold"), background="#F5F5F7", foreground="#1D1D1F")
        except Exception:
            pass

