        def _smtp_entry(row, label, var, placeholder="", show=""):
            ctk.CTkLabel(smtp_grid, text=label, text_color="#6E6E73", font=ctk.CTkFont(size=11)).grid(row=row, column=0, sticky="w", pady=3)
            entry = ctk.CTkEntry(smtp_grid, textvariable=var, placeholder_text=placeholder, show=show, height=32, fg_color="#F5F5F7", border_color="#D1D1D6")
            entry.grid(row=row, column=1, sticky="ew", padx=(8, 0), pady=3)
            return entry

        smtp_grid.grid_columnconfigure(1, weight=1)
        _smtp_entry(0, "SMTP", self.smtp_host_var, "smtp.qq.com")
        _smtp_entry(1, "端口", self.smtp_port_var, "465")
        _smtp_entry(2, "账号", self.smtp_user_var, "sender@qq.com")
        self.smtp_password_entry = _smtp_entry(3, "授权码", self.smtp_password_var, "SMTP 授权码", show="*")
