    def _any_book_task_running(self) -> bool:
        """提示词模板是全局配置；任一任务运行时都不允许保存改动。"""
        try:
            return any(bool(slot.get("is_running")) for slot in getattr(self, "book_slots", []) if isinstance(slot, dict))
        except Exception:
            return bool(state.get("is_running"))

    def _block_prompt_save_while_running(self, parent=None) -> bool:
        if self._any_book_task_running():
            messagebox.showwarning(
                "正在运行",
                "当前有任务正在运行，不能保存提示词或后处理参数。\n\n可以继续查看和编辑；请等所有任务结束后再保存。",
                parent=parent,
            )
            return True
        return False

    def _open_prompt_center(self):
        """打开用户友好的双提示词编辑窗口。"""
        style_key = normalize_content_style(self.content_style_var.get()) if hasattr(self, "content_style_var") else get_active_content_style()
        templates = load_prompt_templates(style_key)
        win = ctk.CTkToplevel(self.root)
        win.title("提示词与后处理")
        win.geometry("1180x820")
        win.minsize(1020, 720)
        win.configure(fg_color="#F5F5F7")
        win.grab_set()

        win.grid_columnconfigure(0, weight=1)
        win.grid_rowconfigure(1, weight=1)
        header = ctk.CTkFrame(win, fg_color="transparent")
        header.grid(row=0, column=0, sticky="ew", padx=18, pady=(16, 8))
        ctk.CTkLabel(header, text="提示词与后处理", font=ctk.CTkFont(size=22, weight="bold"), text_color="#1D1D1F").pack(side="left")
        ctk.CTkLabel(header, text=f"当前风格：{style_key}。运行中可查看和编辑，保存会被拦截。", font=ctk.CTkFont(size=12), text_color="#6E6E73").pack(side="left", padx=(14, 0))

        tabview = ctk.CTkTabview(win, fg_color="#FFFFFF", segmented_button_fg_color="#E5E5EA")
        tabview.grid(row=1, column=0, sticky="nsew", padx=18, pady=8)
        tab_script = tabview.add("脚本")
        tab_polish = tabview.add("润色")
        tab_postprocess = tabview.add("后处理")
        editors = {}

        postprocess_natural_box = None
        postprocess_ai_button = None
        postprocess_status_label = None

        def call_ai_to_fixed_postprocess():
            nonlocal postprocess_ai_button, postprocess_status_label
            if self._block_prompt_save_while_running(parent=win):
                return
            natural_box = postprocess_natural_box
            fixed_box = editors.get("postprocess_requirements")
            if natural_box is None or fixed_box is None:
                messagebox.showerror("无法规范化", "后处理输入框没有初始化。", parent=win)
                return
            natural = natural_box.get("1.0", "end-1c").strip()
            if not natural:
                messagebox.showwarning("缺少要求", "请先在上方输入新的后处理要求，例如：封面标题再下移一点，结尾卡片更透明。", parent=win)
                return
            engine = "GPT-5.5"
            postprocess_ai_button.configure(state="disabled", text="AI 正在转换并应用...")
            if postprocess_status_label is not None:
                postprocess_status_label.configure(text=f"正在调用 {describe_text_engine(engine)} 转成固定参数，并准备自动应用...")

            current_fixed = fixed_box.get("1.0", "end-1c")

            def worker():
                try:
                    fixed_json = normalize_postprocess_requirements_with_llm(
                        natural,
                        current_fixed,
                        engine,
                        self.log,
                        check_cancel=lambda: False,
                        grok_key=self.grok_key_var.get() if hasattr(self, "grok_key_var") else load_grok_api_key(),
                        gemini_key=self.gemini_key_var.get() if hasattr(self, "gemini_key_var") else load_gemini_api_key(),
                        openai_key=self.openai_key_var.get() if hasattr(self, "openai_key_var") else load_openai_api_key(),
                        chatshare_key="",
                    )
                    def done():
                        postprocess_ai_button.configure(state="normal", text="AI 自动转并应用")
                        if fixed_json:
                            fixed_box.delete("1.0", "end")
                            fixed_box.insert("1.0", fixed_json)
                            data = collect()
                            saved = save_prompt_templates(data, style_key)
                            if saved:
                                refresh_postprocess_runtime_config(logger=self.log)
                                self.log("✅ AI 已将自然语言后处理要求转换为固定参数，并自动保存生效。")
                                if postprocess_status_label is not None:
                                    postprocess_status_label.configure(text="已自动转换、写入参数框，并保存生效。")
                                messagebox.showinfo("已自动应用", "大模型已把模糊要求转换为固定后处理参数，并已自动保存生效。\n\n下一次生成或文件夹后处理会直接使用这套参数。", parent=win)
                            else:
                                if postprocess_status_label is not None:
                                    postprocess_status_label.configure(text="已转换，但自动保存失败。请手动保存。")
                                messagebox.showwarning("已转换但未保存", "已转换为固定参数并写入下方参数框，但保存失败。请检查权限后点击“保存并用于运行”。", parent=win)
                        else:
                            if postprocess_status_label is not None:
                                postprocess_status_label.configure(text="转换失败：没有得到可解析 JSON。")
                            messagebox.showwarning("转换失败", "大模型没有返回可解析的 JSON。可以换一个模型，或把要求写得更具体。", parent=win)
                    win.after(0, done)
                except Exception as e:
                    def fail():
                        postprocess_ai_button.configure(state="normal", text="AI 自动转并应用")
                        if postprocess_status_label is not None:
                            postprocess_status_label.configure(text="转换失败。")
                        messagebox.showerror("转换失败", str(e)[:300], parent=win)
                    win.after(0, fail)

            threading.Thread(target=worker, daemon=True).start()

        def build_tab(tab, key, helper):
            tab.grid_columnconfigure(0, weight=1)
            tab.grid_rowconfigure(3, weight=1)
            is_script = key == "script_generation"
            title = "脚本提示词" if is_script else "润色提示词"
            placeholder = (
                "例如：更有故事感；不要‘从心理学角度看’这种解读腔；开头、33%、67%都要有钩子；更能引起共鸣。"
                if is_script else
                "例如：润色时保留逐句锁定，只修顺口和死板解读腔；不要把克制稿子改浮夸。"
            )
            ctk.CTkLabel(tab, text=helper + "\n可以先在上方输入模糊要求，点击 AI 自动转并应用；也可以直接编辑下方完整模板。运行中允许查看和编辑，但保存会被拦截。转换固定使用 GPT-5.5。", text_color="#6E6E73", font=ctk.CTkFont(size=12), wraplength=980, justify="left").grid(row=0, column=0, sticky="ew", padx=12, pady=(10, 6))

            natural_frame = ctk.CTkFrame(tab, fg_color="#F5F7FB", corner_radius=14, border_width=1, border_color="#E5E5EA")
            natural_frame.grid(row=1, column=0, sticky="ew", padx=12, pady=(0, 8))
            natural_frame.grid_columnconfigure(0, weight=1)
            natural_box = ctk.CTkTextbox(
                natural_frame,
                height=108,
                font=ctk.CTkFont(family="Microsoft YaHei UI", size=12),
                wrap="word",
                fg_color="#FFFFFF",
                border_width=0,
                text_color="#1D1D1F",
            )
            natural_box.grid(row=0, column=0, sticky="ew", padx=10, pady=(10, 8))
            natural_box.insert("1.0", placeholder)
            action_row = ctk.CTkFrame(natural_frame, fg_color="transparent")
            action_row.grid(row=1, column=0, sticky="ew", padx=10, pady=(0, 10))

            box = ctk.CTkTextbox(tab, font=ctk.CTkFont(family="Consolas", size=12), wrap="word", fg_color="#FBFBFD", border_width=1, border_color="#E5E5EA", text_color="#1D1D1F")
            box.grid(row=3, column=0, sticky="nsew", padx=12, pady=(0, 12))
            box.insert("1.0", templates.get(key, default_prompt_templates(style_key).get(key, "")))
            editors[key] = box

            status_label = ctk.CTkLabel(action_row, text="保存后生效。", text_color="#6E6E73", font=ctk.CTkFont(size=11))

            def call_ai_to_fixed_prompt():
                if self._block_prompt_save_while_running(parent=win):
                    return
                natural = natural_box.get("1.0", "end-1c").strip()
                if not natural:
                    messagebox.showwarning("缺少要求", f"请先输入新的{title}要求，例如：{placeholder}", parent=win)
                    return
                engine = "GPT-5.5"
                ai_button.configure(state="disabled", text="AI 正在转换并应用...")
                status_label.configure(text=f"正在调用 {describe_text_engine(engine)} 整合为完整{title}...")
                current_fixed = box.get("1.0", "end-1c")

                def worker():
                    try:
                        fixed_prompt = normalize_prompt_template_with_llm(
                            natural,
                            current_fixed,
                            key,
                            style_key,
                            engine,
                            self.log,
                            check_cancel=lambda: False,
                            grok_key=self.grok_key_var.get() if hasattr(self, "grok_key_var") else load_grok_api_key(),
                            gemini_key=self.gemini_key_var.get() if hasattr(self, "gemini_key_var") else load_gemini_api_key(),
                            openai_key=self.openai_key_var.get() if hasattr(self, "openai_key_var") else load_openai_api_key(),
                            chatshare_key="",
                        )
                        def done():
                            ai_button.configure(state="normal", text="AI 自动转并应用")
                            if fixed_prompt:
                                box.delete("1.0", "end")
                                box.insert("1.0", fixed_prompt)
                                data = collect()
                                saved = save_prompt_templates(data, style_key)
                                if saved:
                                    refresh_postprocess_runtime_config(logger=self.log)
                                    self.log(f"✅ AI 已将自然语言要求转换为完整{title}，并自动保存生效。")
                                    status_label.configure(text="已自动转换、写入模板框，并保存生效。")
                                    messagebox.showinfo("已自动应用", f"大模型已把模糊要求整合进完整{title}，并已自动保存生效。\n\n下一次生成会直接使用这套模板。", parent=win)
                                else:
                                    status_label.configure(text="已转换，但自动保存失败。请手动保存。")
                                    messagebox.showwarning("已转换但未保存", f"已转换为完整{title}并写入下方模板框，但保存失败。请检查权限后点击“保存并用于运行”。", parent=win)
                            else:
                                status_label.configure(text="转换失败：没有得到可用模板。")
                                messagebox.showwarning("转换失败", "大模型没有返回可用的完整模板。可以换一个模型，或把要求写得更具体。", parent=win)
                        win.after(0, done)
                    except Exception as e:
                        def fail():
                            ai_button.configure(state="normal", text="AI 自动转并应用")
                            status_label.configure(text="转换失败。")
                            messagebox.showerror("转换失败", str(e)[:300], parent=win)
                        win.after(0, fail)

                threading.Thread(target=worker, daemon=True).start()

            ai_button = ctk.CTkButton(
                action_row,
                text="AI 自动转并应用",
                height=32,
                fg_color="#5856D6",
                hover_color="#4240B8",
                command=call_ai_to_fixed_prompt,
            )
            ai_button.pack(side="left")
            status_label.pack(side="left", padx=(10, 0))

            ctk.CTkLabel(tab, text=f"完整{title}模板（可手动编辑）。", text_color="#6E6E73", font=ctk.CTkFont(size=12), wraplength=980, justify="left").grid(row=2, column=0, sticky="ew", padx=12, pady=(2, 6))

        def build_postprocess_tab(tab):
            nonlocal postprocess_natural_box, postprocess_ai_button, postprocess_status_label
            tab.grid_columnconfigure(0, weight=1)
            tab.grid_rowconfigure(3, weight=1)
            ctk.CTkLabel(
                tab,
                text="输入自然语言要求，AI 会自动转为固定参数。运行中允许查看和编辑，但保存会被拦截。",
                text_color="#6E6E73",
                font=ctk.CTkFont(size=12),
                wraplength=980,
                justify="left",
            ).grid(row=0, column=0, sticky="ew", padx=12, pady=(10, 6))
            natural_frame = ctk.CTkFrame(tab, fg_color="#F5F7FB", corner_radius=14, border_width=1, border_color="#E5E5EA")
