                write_text_file(path, "【脚本生成】\n" + data.get("script_generation", "") + "\n\n【润色台词】\n" + data.get("voiceover_polish", "") + "\n\n【后处理参数】\n" + data.get("postprocess_requirements", "") + "\n")
