    def _select_pdf(self):
        path = filedialog.askopenfilename(filetypes=[("PDF文件", "*.pdf")])
        if path:
            path = self._clean_path(path)
            self.pdf_var.set(path)
            base_name = os.path.splitext(os.path.basename(path))[0]
            safe_base_name = base_name[:35].strip(' ._') if len(base_name) > 35 else base_name.strip(' ._')
            default_out = os.path.join(os.path.dirname(path), f"{safe_base_name}_章节PDF直传结果")
            self.out_var.set(default_out)
            state["current_toc"] = []
            state["current_pdf_path"] = path
            state["pdf_path"] = path
            state["out_dir"] = default_out
            if hasattr(self, "toc_tree"):
                self.refresh_tree([])
            self._save_task_page_settings(log=False)
            self.log("已导入书籍 PDF，正在自动提取目录。")
            task_queue.put({"action": "EXTRACT", "pdf_path": path, "auto": True, "job_state": state, "slot_index": state.get("slot_index", self.active_slot_index)})

    def _select_output_folder(self):
        path = filedialog.askdirectory(title="选择输出文件夹")
        if path:
            self.out_var.set(self._clean_path(path))
            self._save_task_page_settings(log=False)
            self.log(f"输出目录：{self.out_var.get()}")

