    def _sync_api_key_panels(self):
        """刷新模型摘要和 Key 使用状态。"""
        if not hasattr(self, "text_engine_var"):
            return
        self._update_openai_key_status()
        self._update_gemini_key_status()
        self._update_image_key_status()
        self._update_deepseek_key_status()
        script_engine = self.text_engine_var.get()
        review_engine = resolve_review_engine(self.review_engine_var.get(), script_engine) if hasattr(self, "review_engine_var") else script_engine
        image_engine = self.image_engine_var.get() if hasattr(self, "image_engine_var") else IMAGE_ENGINE_GPT_IMAGE2
        needs = []
        if is_openai_text_engine(script_engine) or is_openai_text_engine(review_engine): needs.append("GPT Key")
        if is_gemini_text_engine(script_engine) or is_gemini_text_engine(review_engine): needs.append("Gemini Key")
        if is_openai_image_engine(image_engine) or is_gemini_image_engine(image_engine): needs.append("生图专用 Key")
        if is_deepseek_text_engine(script_engine) or is_deepseek_text_engine(review_engine): needs.append("DeepSeek Key")
        if hasattr(self, "model_summary_label"):
            self.model_summary_label.configure(text=f"脚本初稿：{describe_text_engine(script_engine)}\n全文终审：{describe_text_engine(review_engine)}\n分镜配图：{describe_image_engine(image_engine)}\n当前配置需要：{'、'.join(needs) if needs else '无'}")

