    def _save_api_key_if_present(self, name, var_attr, sanitizer, validator, saver):
        if not hasattr(self, var_attr):
            return "missing"
        key = sanitizer(getattr(self, var_attr).get())
        if not key:
            return "empty"
        if not validator(key):
            return "invalid"
        getattr(self, var_attr).set(key)
        return "saved" if saver(key) else "failed"

    def _save_all_api_keys(self, quiet=False):
        checks = [
            ("DeepSeek", "deepseek_key_var", sanitize_deepseek_api_key, is_valid_deepseek_api_key, save_deepseek_api_key),
            ("GPT", "openai_key_var", sanitize_openai_api_key, is_valid_openai_api_key, save_openai_api_key),
            ("Gemini", "gemini_key_var", sanitize_gemini_api_key, is_valid_gemini_api_key, save_gemini_api_key),
            ("生图专用", "image_key_var", sanitize_openai_api_key, is_valid_openai_api_key, save_image_api_key),
        ]
        saved = []
        invalid = []
        failed = []
        for name, var_attr, sanitizer, validator, saver in checks:
            status = self._save_api_key_if_present(name, var_attr, sanitizer, validator, saver)
            if status == "saved":
                saved.append(name)
            elif status == "invalid":
                invalid.append(name)
            elif status == "failed":
                failed.append(name)
        self._sync_api_key_panels()
        if not quiet:
            if saved:
                self.log("🔑 已保存 API Key：" + "、".join(saved))
            if invalid:
                self.log("⚠️ 以下 API Key 格式待确认，未保存：" + "、".join(invalid))
            if failed:
                self.log("⚠️ 以下 API Key 写入失败：" + "、".join(failed))
            if not saved and not invalid and not failed:
                self.log("ℹ️ 没有检测到需要保存的 API Key。")
        return not invalid and not failed

    def _save_deepseek_key(self):
        key = sanitize_deepseek_api_key(self.deepseek_key_var.get())
        if not key:
            messagebox.showwarning("缺少Key", "请先在输入框里填入 DeepSeek API Key。")
            return False
        if not is_valid_deepseek_api_key(key):
            messagebox.showwarning("Key格式待确认", "请确认只粘贴 DeepSeek API Key，不要包含 Bearer、空格、换行或多余字符。")
            self.log("⚠️ DeepSeek Key 格式待确认。")
            return False
        self.deepseek_key_var.set(key)
        if save_deepseek_api_key(key):
            self._sync_api_key_panels(); self.log(f"DeepSeek Key 已保存：{DEEPSEEK_KEY_FILE}")
            return True
        return False

    def _save_current_model_scheme(self, log=True):
        if not hasattr(self, "text_engine_var"):
            return
        scheme = {
            "text_engine": self.text_engine_var.get(),
            "review_engine": self.review_engine_var.get(),
            "image_engine": self.image_engine_var.get(),
            "call_mode": self.call_mode_var.get() if hasattr(self, "call_mode_var") else WEB_CALL_MODE_API,
            "flow_parse": bool(self.flow_parse_var.get()) if hasattr(self, "flow_parse_var") else True,
            "flow_script": bool(self.flow_script_var.get()) if hasattr(self, "flow_script_var") else True,
            "flow_image": bool(self.flow_image_var.get()) if hasattr(self, "flow_image_var") else True,
            "clear_existing_images_before_draw": bool(self.clear_existing_images_var.get()) if hasattr(self, "clear_existing_images_var") else False,
            "direct_pdf_to_llm": False,
            "content_style": normalize_content_style(self.content_style_var.get()) if hasattr(self, "content_style_var") else get_active_content_style(),
            "email_after_completion": bool(self.email_after_completion_var.get()) if hasattr(self, "email_after_completion_var") else False,
            "email_recipient": normalize_email_recipient(self.email_recipient_var.get()) if hasattr(self, "email_recipient_var") else "",
            "daily_skip_medical_related": bool(self.daily_skip_medical_related_var.get()) if hasattr(self, "daily_skip_medical_related_var") else False,
        }
        self.model_scheme = scheme
        self._capture_active_slot_from_ui()
        ok = save_model_scheme(scheme)
        if log and ok:
            self.log(f"模型方案已保存，下次启动会自动恢复：{MODEL_SCHEME_FILE}")

    def _save_task_page_settings(self, log=False):
        if not hasattr(self, "book_slots"):
            return False
        try:
            self._capture_active_slot_from_ui()
        except Exception:
            pass
        ok = save_task_page_settings({"slots": getattr(self, "book_slots", [])})
        if ok:
            try:
                self.task_page_settings = load_task_page_settings()
            except Exception:
                pass
        if log and ok:
            self.log(f"任务页面设置已保存：{TASK_PAGE_SETTINGS_FILE}")
        return ok

    def _current_smtp_identity(self):
        user = str(self.smtp_user_var.get()).strip() if hasattr(self, "smtp_user_var") else ""
        sender = str(self.smtp_from_var.get()).strip() if hasattr(self, "smtp_from_var") else ""
        recipient = normalize_email_recipient(self.email_recipient_var.get()) if hasattr(self, "email_recipient_var") else ""
        return user or sender or recipient

    def _looks_like_smtp_host(self, host: str) -> bool:
        host = str(host or "").strip()
        if not host or "@" in host or " " in host:
            return False
        return "." in host and re.match(r"^[A-Za-z0-9.-]+$", host) is not None

    def _apply_smtp_provider_preset(self, force=False):
        identity = self._current_smtp_identity().lower()
        host = str(self.smtp_host_var.get()).strip() if hasattr(self, "smtp_host_var") else ""
        if force or identity.endswith("@qq.com") or (host and not self._looks_like_smtp_host(host)):
            if hasattr(self, "smtp_host_var"):
                self.smtp_host_var.set("smtp.qq.com")
            if hasattr(self, "smtp_port_var"):
                self.smtp_port_var.set("465")
            if hasattr(self, "smtp_ssl_var"):
                self.smtp_ssl_var.set(True)
            if hasattr(self, "smtp_tls_var"):
                self.smtp_tls_var.set(False)
            if hasattr(self, "smtp_from_var") and not str(self.smtp_from_var.get()).strip() and hasattr(self, "smtp_user_var"):
                self.smtp_from_var.set(str(self.smtp_user_var.get()).strip())
            self.log("📮 已应用 QQ 邮箱 SMTP 预设：smtp.qq.com / 465 / SSL。")
            return True
        return False

    def _validate_smtp_fields_before_save(self):
        self._apply_smtp_provider_preset(force=False)
        try:
            smtp_port = int(str(self.smtp_port_var.get()).strip() or "465") if hasattr(self, "smtp_port_var") else 465
        except Exception:
            messagebox.showwarning("端口无效", "SMTP 端口必须是数字，例如 QQ 邮箱使用 465。")
            return None
        smtp_host = str(self.smtp_host_var.get()).strip() if hasattr(self, "smtp_host_var") else ""
        smtp_user = str(self.smtp_user_var.get()).strip() if hasattr(self, "smtp_user_var") else ""
        smtp_password = str(self.smtp_password_var.get()).strip() if hasattr(self, "smtp_password_var") else ""
        smtp_from = str(self.smtp_from_var.get()).strip() if hasattr(self, "smtp_from_var") else ""
        if smtp_user.endswith("@qq.com") and not smtp_from:
            smtp_from = smtp_user
            if hasattr(self, "smtp_from_var"):
                self.smtp_from_var.set(smtp_from)
        if smtp_host and not self._looks_like_smtp_host(smtp_host):
            messagebox.showwarning("SMTP服务器无效", "SMTP 服务器应填写主机名，例如 QQ 邮箱是 smtp.qq.com；授权码请填写在“授权码”栏。")
            self.log("⚠️ SMTP 保存失败：服务器地址无效，请填写 smtp.qq.com 这类主机名。")
            return None
        return smtp_host, smtp_port, smtp_user, smtp_password, smtp_from

    def _save_email_settings(self):
        self._capture_active_slot_from_ui()
        recipient = normalize_email_recipient(self.email_recipient_var.get()) if hasattr(self, "email_recipient_var") else ""
        enabled = bool(self.email_after_completion_var.get()) if hasattr(self, "email_after_completion_var") else False
        if enabled and not parse_email_recipients(recipient):
            messagebox.showwarning("邮箱格式无效", "请填写有效收件邮箱；多个邮箱可用逗号分隔。")
            self.log("⚠️ 邮箱保存失败：收件邮箱为空或格式无效。")
            return False
        validated = self._validate_smtp_fields_before_save()
        if not validated:
            return False
        smtp_host, smtp_port, smtp_user, smtp_password, smtp_from = validated
        payload = {
            "smtp_host": smtp_host,
            "smtp_port": smtp_port,
            "smtp_user": smtp_user,
            "smtp_password": smtp_password,
            "smtp_from": smtp_from,
            "smtp_ssl": bool(self.smtp_ssl_var.get()) if hasattr(self, "smtp_ssl_var") else True,
            "smtp_tls": bool(self.smtp_tls_var.get()) if hasattr(self, "smtp_tls_var") else False,
            "note": "由界面保存。授权码仅用于 SMTP 登录，请勿公开分享。",
        }
        try:
            with open(EMAIL_DELIVERY_SETTINGS_FILE, "w", encoding="utf-8") as f:
                json.dump(payload, f, ensure_ascii=False, indent=2)
        except Exception as e:
            self.log(f"⚠️ 邮箱 SMTP 配置保存失败：{str(e)[:120]}")
            messagebox.showwarning("保存失败", f"无法写入邮箱配置：{str(e)[:80]}")
            return False
        if self._save_task_page_settings(log=False):
            self.log("📮 邮箱配置已保存。")
        return True

    def _toggle_smtp_password_visibility(self):
        if not hasattr(self, "smtp_password_entry"):
            return
        current = self.smtp_password_entry.cget("show")
        self.smtp_password_entry.configure(show="" if current == "*" else "*")

