    def _default_daily_journal_text(self):
        journals = globals().get("DAILY_RESEARCH_DEFAULT_JOURNALS", [])
        if not journals:
            journals = ["Nature Neuroscience", "Neuron", "Nature", "Science", "Cell", "Nature Methods", "Nature Medicine", "Brain", "Journal of Neuroscience", "PNAS", "eLife"]
        return "\n".join(str(j).strip() for j in journals if str(j).strip())

